require "data.TaskPoolManager"

TaskConfig = {}
TaskConfig.TaskLevelGroup = {}
TaskConfig.TaskList = {}

function TaskConfig:initTaskLevelGroupConfig(group_list)
    for _, group in pairs(group_list) do
        local item = {
            Id = tonumber(group.Id),
            TaskType = tonumber(group.TaskType),
            MinLevel = tonumber(group.MinLevel),
            MaxLevel = tonumber(group.MaxLevel),
            MainPoolId = tonumber(group.MainGroupId),
            RandomPoolId = tonumber(group.RandomGroupId),
            TaskCount = tonumber(group.TaskCount)
        }
        self.TaskLevelGroup[item.Id] = item
    end
end

function TaskConfig:initTaskListConfig(task_list)
    for _, task in pairs(task_list) do
        local item = {
            Id = tonumber(task.Id),
            Title = task.Title or "",
            Icon = task.Icon or "",
            TaskPoolId = tonumber(task.GroupId),
            NextTaskId = tonumber(task.NextTaskId),
            TaskTypeId = tonumber(task.TaskTypeId),
            GoalNum = tonumber(task.GoalNum),
            Remarks = StringUtil.split(task.Remarks, "#"),
            GameType = tonumber(task.GameType),
            ActiveValue = tonumber(task.ActiveValue),
            GameTypes = StringUtil.split(task.GameType, "#"),
            Weight = tonumber(task.Weight),
            SortValue = tonumber(task.SortValue),
            RewardIds = StringUtil.split(task.RewardIds, "#"),
            ShowAd = tonumber(task.ShowAd) == 1
        }
        self.TaskList[item.Id] = item
        TaskPoolManager:putTaskIntoPool(item)
    end
end

function TaskConfig:getTaskDailyGroup(level)
    local data = {}
    for _, group in pairs(self.TaskLevelGroup) do
        if group.TaskType == Define.TaskMain.Daily and
                group.MaxLevel >= level and
                group.MinLevel <= level then
            table.insert(data, group)
        end
    end
    return data
end

function TaskConfig:getTaskMainGroup(level, unlockLevel)
    local data = {}
    if level > unlockLevel then
        for _, group in pairs(self.TaskLevelGroup) do
            if group.TaskType == Define.TaskMain.Mainline and
                    group.MinLevel > unlockLevel and
                    group.MinLevel <= level then
                table.insert(data, group)
            end
        end
    end
    return data
end

function TaskConfig:getTaskById(taskId)
    return self.TaskList[tostring(taskId)]
end

return TaskConfig